import{_ as a,o as i,c as t,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Email to App","description":"","frontmatter":{"title":"Email to App","slug":"email-to-app"},"headers":[],"relativePath":"marketer-hub/email-to-app.md","filePath":"marketer-hub/email-to-app.md"}'),o={name:"marketer-hub/email-to-app.md"};function n(l,e,s,p,c,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<p>.svg &quot;diag-2.svg&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Email is a special channel for marketing teams to re-engage customers to come back to the brand and learn more about new things. This can range from promotional/marketing email campaigns or transactional emails. It is important to be able to provide loyal customers with delightful user experiences. Users with the app installed expect their app to open when clicking on links in email (where appropriate). Branch&#39;s Email feature solves the problems that come with deep linking from email to app.</p><h3 id="branch-email-use-cases" tabindex="-1">Branch Email Use Cases <a class="header-anchor" href="#branch-email-use-cases" aria-label="Permalink to &quot;Branch Email Use Cases&quot;">​</a></h3><ul><li>Deep Linking users to product pages in your app from marketing/promotional emails.</li><li>Drive app installs through email campaigns.</li><li>App re-engagement through deep links for transactional emails.</li></ul><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li>Branch connects with your email service provider for running email campaigns to use Branch Links.</li><li>User clicks a link from an email.</li><li>If user has the app installed: the app opens and routes to relevant content.</li><li>If user doesn&#39;t have the app installed:<br> a. Route user to App/Play store to download the app and routes to relevant content on app open.<br> b. Route user to mobile web relevant content</li></ol><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Branch Email is available as part of our Engagement product. Learn more on our <a href="./packaging.html">pricing</a> page.</p><h2 id="integration-guide" tabindex="-1">Integration Guide <a class="header-anchor" href="#integration-guide" aria-label="Permalink to &quot;Integration Guide&quot;">​</a></h2><p>The integration changes depending on which email service provider you are using. Please follow the <a href="./universal-email-integration-guide.html">Branch Email Integration Guide</a> for your specific email service provider.</p>',11)])])}const d=a(o,[["render",n]]);export{u as __pageData,d as default};
